(function () {
  const GRIDS = ['grid-de', 'grid-en', 'grid-sci', 'grid-did'];

  // ── Card size ──
  let cardSize = parseInt(localStorage.getItem('cardSize') || '160');
  applySize();

  function applySize() {
    document.documentElement.style.setProperty('--card-min-width', cardSize + 'px');
  }

  window.adjustSize = function (delta) {
    cardSize = Math.max(100, Math.min(320, cardSize + delta));
    localStorage.setItem('cardSize', cardSize);
    applySize();
  };

  // ── Collapse / expand ──
  window.toggleSection = function (gridId) {
    const grid = document.getElementById(gridId);
    const btn  = document.getElementById('btn-' + gridId);
    const isCollapsed = grid.classList.toggle('collapsed');
    btn.classList.toggle('collapsed', isCollapsed);
    localStorage.setItem('collapsed-' + gridId, isCollapsed);
  };

  GRIDS.forEach(id => {
    if (localStorage.getItem('collapsed-' + id) === 'true') {
      const grid = document.getElementById(id);
      const btn  = document.getElementById('btn-' + id);
      if (grid) grid.classList.add('collapsed');
      if (btn)  btn.classList.add('collapsed');
    }
  });

  // ── Drag & drop ──
  let dragSrc = null;

  function initDrag(grid) {
    // Restore saved order
    const saved = localStorage.getItem('order-' + grid.id);
    if (saved) {
      try {
        const ids = JSON.parse(saved);
        ids.forEach(id => {
          const card = grid.querySelector('[data-id="' + id + '"]');
          if (card) grid.appendChild(card);
        });
      } catch (e) {}
    }

    grid.querySelectorAll('.news-card').forEach(card => {
      card.draggable = true;

      card.addEventListener('dragstart', function (e) {
        dragSrc = this;
        this.classList.add('dragging');
        e.dataTransfer.effectAllowed = 'move';
        // allow click-through after drag
        e.dataTransfer.setData('text/plain', this.dataset.id);
      });

      card.addEventListener('dragend', function () {
        this.classList.remove('dragging');
        document.querySelectorAll('.news-card').forEach(c => c.classList.remove('drag-over'));
      });

      card.addEventListener('dragover', function (e) {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
        if (dragSrc && dragSrc !== this && dragSrc.parentNode === this.parentNode) {
          document.querySelectorAll('.news-card').forEach(c => c.classList.remove('drag-over'));
          this.classList.add('drag-over');
        }
      });

      card.addEventListener('drop', function (e) {
        e.preventDefault();
        e.stopPropagation();
        this.classList.remove('drag-over');
        if (!dragSrc || dragSrc === this) return;
        if (dragSrc.parentNode !== this.parentNode) return;

        const parent = this.parentNode;
        const cards  = [...parent.children];
        const srcIdx = cards.indexOf(dragSrc);
        const tgtIdx = cards.indexOf(this);

        if (srcIdx < tgtIdx) {
          parent.insertBefore(dragSrc, this.nextSibling);
        } else {
          parent.insertBefore(dragSrc, this);
        }

        // Save new order
        const order = [...parent.children].map(c => c.dataset.id);
        localStorage.setItem('order-' + parent.id, JSON.stringify(order));
      });

      // Prevent drag from triggering link navigation
      card.addEventListener('click', function (e) {
        if (dragSrc) { e.preventDefault(); dragSrc = null; }
      });
    });
  }

  GRIDS.forEach(id => {
    const grid = document.getElementById(id);
    if (grid) initDrag(grid);
  });
})();
</script>
